"use client";

import Image from "next/image";
import { useState, useCallback, useMemo } from "react";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { OrderSummary, type OrderItem } from "@/components/OrderSummary";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { Badge } from "./ui/badge";

export type Vendor = {
  id: string;
  name: string;
  description: string;
};

export type MenuItem = {
  id: string;
  name: string;
  price: number;
  imageUrl: string;
  aiHint: string;
};

export type Menu = {
  [key: string]: MenuItem[];
};

interface OrderClientProps {
  vendors: Vendor[];
  menus: Menu;
}

export function OrderClient({ vendors, menus }: OrderClientProps) {
  const [selectedVendor, setSelectedVendor] = useState<Vendor | null>(vendors[0] || null);
  const [order, setOrder] = useState<OrderItem[]>([]);
  const { toast } = useToast();

  const handleSelectVendor = useCallback((vendor: Vendor) => {
    if (order.length > 0 && selectedVendor?.id !== vendor.id) {
       toast({
        variant: "destructive",
        title: "尚有未完成訂單",
        description: "切換店家將會清空目前的訂單，請先完成或取消訂單。",
      });
      return;
    }
    setSelectedVendor(vendor);
  }, [order.length, selectedVendor?.id, toast]);

  const handleAddToOrder = useCallback((item: MenuItem, vendor: Vendor) => {
    if (selectedVendor && selectedVendor.id !== vendor.id) {
      toast({
        variant: "destructive",
        title: "跨店點餐失敗",
        description: "一次只能訂購同一家店的餐點喔！",
      });
      return;
    }

    if (!selectedVendor) {
      setSelectedVendor(vendor);
    }
    
    setOrder((prevOrder) => {
      const existingItem = prevOrder.find((orderItem) => orderItem.id === item.id);
      if (existingItem) {
        return prevOrder.map((orderItem) =>
          orderItem.id === item.id
            ? { ...orderItem, quantity: orderItem.quantity + 1 }
            : orderItem
        );
      }
      return [...prevOrder, { ...item, quantity: 1, vendorName: vendor.name }];
    });

    toast({
      title: "已加入訂單",
      description: `${item.name} 已新增至您的訂單。`,
    });

  }, [selectedVendor, toast]);

  const handleUpdateQuantity = useCallback((itemId: string, quantity: number) => {
    setOrder((prevOrder) => {
      if (quantity <= 0) {
        return prevOrder.filter((item) => item.id !== itemId);
      }
      return prevOrder.map((item) =>
        item.id === itemId ? { ...item, quantity } : item
      );
    });
  }, []);

  const handleSubmitOrder = useCallback(() => {
    if (order.length === 0) {
       toast({
        variant: "destructive",
        title: "訂單是空的",
        description: "請先選擇餐點再送出訂單。",
      });
      return;
    }
    // In a real application, this would send the order to the Google Sheets API.
    console.log("Order Submitted:", order);
    toast({
      title: "訂單已送出！",
      description: "感謝您的訂購，請記得付款喔！",
    });
    setOrder([]);
    setSelectedVendor(null);
  }, [order, toast]);

  const selectedMenu = useMemo(() => {
    if (!selectedVendor) return [];
    return menus[selectedVendor.id] || [];
  }, [selectedVendor, menus]);

  return (
    <div className="container mx-auto max-w-screen-xl p-4 sm:p-6 lg:p-8">
      <div className="grid grid-cols-1 lg:grid-cols-3 lg:gap-8">
        <div className="lg:col-span-2 space-y-8">
          {/* Vendor Selection */}
          <section>
            <h2 className="font-headline text-2xl font-bold mb-4">今日店家</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
              {vendors.map((vendor) => (
                <Card
                  key={vendor.id}
                  onClick={() => handleSelectVendor(vendor)}
                  className={cn(
                    "cursor-pointer transition-all duration-200 hover:shadow-lg hover:-translate-y-1",
                    selectedVendor?.id === vendor.id && "ring-2 ring-primary shadow-lg"
                  )}
                >
                  <CardHeader>
                    <CardTitle className="font-headline">{vendor.name}</CardTitle>
                    <CardDescription className="font-body">{vendor.description}</CardDescription>
                  </CardHeader>
                </Card>
              ))}
            </div>
          </section>

          {/* Menu Display */}
          {selectedVendor && (
            <section>
              <h2 className="font-headline text-2xl font-bold mb-4">{selectedVendor.name} 菜單</h2>
              <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-6">
                {selectedMenu.map((item) => (
                  <Card key={item.id} className="flex flex-col overflow-hidden transition-shadow hover:shadow-xl">
                    <div className="relative h-48 w-full">
                      <Image
                        src={item.imageUrl}
                        alt={item.name}
                        fill
                        className="object-cover"
                        data-ai-hint={item.aiHint}
                      />
                    </div>
                    <CardHeader>
                      <CardTitle className="font-headline">{item.name}</CardTitle>
                    </CardHeader>
                    <CardContent className="flex-grow">
                      <Badge variant="secondary" className="font-sans text-lg">${item.price}</Badge>
                    </CardContent>
                    <CardFooter>
                      <Button className="w-full" onClick={() => handleAddToOrder(item, selectedVendor)}>
                        加入訂單
                      </Button>
                    </CardFooter>
                  </Card>
                ))}
              </div>
            </section>
          )}
        </div>

        {/* Order Summary */}
        <aside className="pt-8 lg:pt-0">
          <div className="lg:sticky lg:top-24">
            <OrderSummary
              order={order}
              onUpdateQuantity={handleUpdateQuantity}
              onSubmit={handleSubmitOrder}
            />
          </div>
        </aside>
      </div>
    </div>
  );
}
